var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"레지나! 거기 서서 뭐 하는 거야?","JPN":"レジーナ！　そこに突っ立って何してるの？","ENG":"Regina! What are you doing over there?","TWN":"蕾佳娜！妳站那裡做什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델도 오래 버티지는 못 할거야. 지금 도망쳐야 해.","JPN":"エデルも長くはもたないよ。今逃げなきゃ。","ENG":"Edel won't be able to stall that thing for very long. We should run now.","TWN":"艾瑟兒也撐不了多久的。我們得趕快逃走才行。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무래도 안 되겠어요.","JPN":"やっぱりダメです。","ENG":"This isn't right.","TWN":"不行。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"돌아가야겠어요. 에델이 저 괴물에게 잡아 먹히게 둘 수는 없어요.","JPN":"戻らないと。エデルがあの怪物に食われるのを黙って見ているわけにはいきませんわ。","ENG":"I'm going back. I can't let that monster feed on Edel.","TWN":"我得回去。我不能讓艾瑟兒被那個怪物吃掉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뭐어?","JPN":"はあ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델은 분명 제가 끔찍하게 싫어하는 학회의 사람이지만......","JPN":"エデルは確かに私の大嫌いな学会の人間ですが……","ENG":"Edel is a member of an organization that I absolutely abhor,","TWN":"雖然艾瑟兒是我極為憎恨的學會會員……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"또한 제가 지켜야 하는 맥크레디 영지의 영민이기도 해요.","JPN":"私が守るべきマクレディーの領地の民でもあるのです。","ENG":"but at the same time, she's a resident of the MacCready Estate, whom I'm supposed to protect.","TWN":"但她也是我必須保護的麥克蕾蒂領地居民。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"더구나 에델이 싸우고 있는 건 제 어머니의 시신으로 만들어진 괴물이잖아요?","JPN":"しかも、エデルが戦っているのは私の母の遺体で作られた怪物です。","ENG":"Besides, Edel is fighting against the monster that grew in my mother's body.","TWN":"況且，與艾瑟兒戰鬥的那個怪物，不就是我母親遺體所變成的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니 제게도 사태를 해결해야 할 책임이 있어요.","JPN":"だから、私にもこの事態を解決すべき責任がありますわ。","ENG":"I also have a responsibility to take care of this.","TWN":"所以我也有解決這件事的責任。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"뭐, 내겐 다 핑계로 들리긴 하는데......","JPN":"何だか、アタシにはただの言い訳にしか聞こえないけど……","ENG":"I'll pretend not to notice that all your arguments are lame excuses,","TWN":"這個嘛，在我聽來都是些藉口啦……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"싸운다면 승산은 있는 거야?","JPN":"戦うとして、勝ち目はあるの？","ENG":"but do you have a plan?","TWN":"但要戰鬥的話，妳有勝算嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......이 곳에 처음 도착했을 때부터 저 제단으로부터 불길한 기운이 느껴졌어요.","JPN":"……ここに初めて到着した時から、あの祭壇に不吉なものを感じていましたわ。","ENG":"In fact, I've had a strange feeling about that altar ever since we got here.","TWN":"……第一次來到這個地方時，我就感覺到祭壇那邊傳來的不祥氣息。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 어떻게 이런 사실을 알고 있는지는 모르겠지만, 분명 확실히 느껴져요.","JPN":"どうしてかはわかりませんが、確かに感じます。","ENG":"I don't know how, but I definitely feel it.","TWN":"雖然不清楚我是怎麼知道的，但我確實感受到了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저것만 부순다면 괴물의 힘도 약해질 거예요!","JPN":"あれさえ壊せば、怪物の力も弱くなるはずです！","ENG":"If we destroy that thing, the monster will lose a lot of its power.","TWN":"只要能把那個破壞掉，怪物的力量也會變弱！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"네. 수고하세요.","JPN":"はい。じゃあ頑張ってください。","ENG":"I see. I wish you good luck, then.","TWN":"好，那妳加油吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니까 도와주세요, 리벳!","JPN":"だから、力を貸してください！　リベット！","ENG":"So help me, Rivet!","TWN":"所以請幫幫我，里維！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괴물이 에델에게 정신이 팔린 지금이 제단을 부술 기회입니다!","JPN":"怪物がエデルに気を取られている今が、祭壇を壊すチャンスなのです！","ENG":"Edel's keeping the monster busy. Now is our chance to destroy that altar!","TWN":"趁怪物被艾瑟兒吸引住的時候，現在就是破壞祭壇的好機會！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에엥~ 그치만 난 레지나 말을 따를 이유가 없는걸~","JPN":"ええ～、でもアタシがレジーナの言うとおりにする理由なんて無いよね～。","ENG":"I get it, but I have no reason to follow your orders.","TWN":"哎呀～可是我沒有理由聽蕾佳娜的話啊～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};